Berikut script Python untuk audit rekursif file permissions. Fokus utama adalah identifikasi celah keamanan seperti *world-writable*, *world-readable* pada file sensitif, atau bit SUID/SGID yang mencurigakan.

Gunakan script ini untuk hardening server atau audit kepatuhan keamanan.

```python
#!/usr/bin/env python3
import os
import stat
import pwd
import grp
import sys

def get_owner_group(path):
    try:
        st = os.stat(path)
        try:
            owner = pwd.getpwuid(st.st_uid).pw_name
        except KeyError:
            owner = st.st_uid
        try:
            group = grp.getgrgid(st.st_gid).gr_name
        except KeyError:
            group = st.st_gid
        return owner, group, st.st_mode
    except Exception as e:
        return "-", "-", None

def check_security_risks(mode, path):
    risks = []
    perms = stat.S_IMODE(mode)

    # Check World Writable
    if perms & stat.S_IWOTH:
        risks.append("WORLD_WRITABLE")

    # Check World Writable + Executable (Dangerous)
    if (perms & stat.S_IWOTH) and (perms & stat.S_IXOTH):
        risks.append("DANGEROUS_EXEC")

    # Check SUID/SGID
    if mode & stat.S_ISUID:
        risks.append("SUID_BIT")
    if mode & stat.S_ISGID:
        risks.append("SGID_BIT")

    # Check World Readable on specific sensitive extensions (optional logic)
    # if path.endswith(('.env', '.key', '.pem')) and (perms & stat.S_IROTH):
    #     risks.append("SENSITIVE_EXPOSED")

    return risks

def audit_directory(root_path):
    print(f"[*] Memulai audit keamanan pada: {os.path.abspath(root_path)}")
    print(f"{'PATH':<60} | {'OWNER':<10} | {'GROUP':<10} | {'PERMS':<10} | {'RISKS'}")
    print("-" * 120)

    for dirpath, dirnames, filenames in os.walk(root_path):
        # Audit Directory
        owner, group, mode = get_owner_group(dirpath)
        if mode:
            risks = check_security_risks(mode, dirpath)
            risk_str = ", ".join(risks) if risks else "OK"
            if risks:
                print(f"\033[91m{dirpath:<60}\033[0m | {owner:<10} | {group:<10} | {oct(stat.S_IMODE(mode)):<10} | \033[91m{risk_str}\033[0m")
            else:
                print(f"{dirpath:<60} | {owner:<10} | {group:<10} | {oct(stat.S_IMODE(mode)):<10} | {risk_str}")

        # Audit Files
        for filename in filenames:
            filepath = os.path.join(dirpath, filename)
            owner, group, mode = get_owner_group(filepath)

            if mode:
                risks = check_security_risks(mode, filepath)
                risk_str = ", ".join(risks) if risks else "OK"
                if risks:
                    print(f"\033[91m{filepath:<60}\033[0m | {owner:<10} | {group:<10} | {oct(stat.S_IMODE(mode)):<10} | \033[91m{risk_str}\033[0m")
                else:
                    print(f"{filepath:<60} | {owner:<10} | {group:<10} | {oct(stat.S_IMODE(mode)):<10} | {risk_str}")
            else:
                print(f"{filepath:<60} | {'ERROR':<10} | {'ERROR':<10} | {'N/A':<10} | ACCESS_DENIED")

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print(f"Usage: {sys.argv[0]} <target_directory>")
        sys.exit(1)

    target = sys.argv[1]
    if not os.path.isdir(target):
        print(f"[!] Error: {target} bukan direktori valid.")
        sys.exit(1)

    try:
        audit_directory(target)
    except KeyboardInterrupt:
        print("\n[!] Audit dihentikan pengguna.")
        sys.exit(0)
```

### Analisis Teknis & Mitigasi

1.  **World Writable (`WORLD_WRITABLE`)**:
    *   **Risiko**: Pengguna lain dapat memodifikasi atau menghapus file. Rawan *defacement* atau injeksi kode.
    *   **Mitigasi**: `chmod o-w <file>` atau `chmod 644 <file>` untuk file, `chmod 755 <dir>` untuk direktori.

2.  **SUID/SGID Bit**:
    *   **Risiko**: File dieksekusi dengan izin pemilik/file (seringkali root). Jika ada kerentanan pada binary/script ini, attacker bisa escalasi privilege.
    *   **Mitigasi**: Hapus bit jika tidak diperlukan: `chmod u-s <file>` atau `chmod g-s <file>`.

3.  **Sensitive Exposed**:
    *   Script ini bisa dikembangkan untuk mendeteksi file `.env`, `.key`, atau `.pem` yang terbaca oleh *others*.
    *   **Mitigasi**: Pastikan file kredensial memiliki permission `600` dan dimiliki oleh user yang menjalankan servis.

Jalankan script dengan user biasa untuk audit umum, atau root untuk audit sistem menyeluruh. Pastikan Anda memiliki izin baca pada direktori target.
